import torch
import torchvision.models as models
import torchvision.transforms as transforms
from torchvision.datasets import ImageFolder
from torch.utils.data import DataLoader
import torch.optim as optim
import torch.nn as nn
import requests
from io import BytesIO

# Function to download the model checkpoint
def download_model(url):
    response = requests.get(url)
    response.raise_for_status()
    return torch.load(BytesIO(response.content))

# Example usage: downloading a ResNet18 model checkpoint
model_url = 'https://download.pytorch.org/models/resnet18-f37072fd.pth'
state_dict = download_model(model_url)

# Load the model architecture
model = models.resnet18()
model.load_state_dict(state_dict)

# Modify the last layer for the desired number of classes
num_classes = 5 # Assuming 5 classes for the custom dataset
model.fc = nn.Linear(model.fc.in_features, num_classes)

# Prepare custom dataset
data_transforms = transforms.Compose([
    transforms.Resize((224, 224)),
    transforms.ToTensor(),
])
train_dataset = ImageFolder('path/to/custom/train_data', transform=data_transforms)
train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)

# Define loss and optimizer
criterion = nn.CrossEntropyLoss()
optimizer = optim.SGD(model.parameters(), lr=0.001, momentum=0.9)

# Fine-tune the model
def fine_tune_model(model, train_loader, criterion, optimizer, num_epochs=5):
    model.train()
    for epoch in range(num_epochs):
        running_loss = 0.0
        for inputs, labels in train_loader:
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {running_loss/len(train_loader):.4f}')

fine_tune_model(model, train_loader, criterion, optimizer)